1766	struct PopulateNetlist : public TimingPatternInterpretor, public ast::ASTVisitor<PopulateNetlist, ast::VisitFlags::Statements> {
1767	public:
1768		HierarchyQueue &queue;
1769		NetlistContext &netlist;
1770		SynthesisSettings &settings;
1771		InferredMemoryDetector mem_detect;
1772		std::vector<NetlistContext> deferred_modules;
1773	
1774		PopulateNetlist(HierarchyQueue &queue, NetlistContext &netlist)
1775			: TimingPatternInterpretor(netlist.settings, (DiagnosticIssuer&) netlist, netlist.eval),
1776			  queue(queue), netlist(netlist), settings(netlist.settings),
1777			  mem_detect(settings, std::bind(&NetlistContext::should_dissolve, &netlist, std::placeholders::_1, nullptr), netlist.eval) {}
1778	
1779		void handle_comb_like_process(const ast::ProceduralBlockSymbol &symbol, const ast::Statement &body)
1780		{
1781			RTLIL::Process *proc = netlist.canvas->addProcess(netlist.new_id());
1782			transfer_attrs(netlist, body, proc);
1783	
1784			ProceduralContext procedure(netlist, ProcessTiming::implicit);
1785			body.visit(StatementExecutor(procedure));
1786	
1787			VariableBits all_driven = procedure.all_driven();
1788			Yosys::pool<VariableBit> dangling;
1789			if (symbol.procedureKind != ast::ProceduralBlockKind::AlwaysComb) {
1790				Yosys::pool<VariableBit> driven_pool = {all_driven.begin(), all_driven.end()};
1791				dangling =
1792					detect_possibly_unassigned_subset(driven_pool, procedure.root_case.get());
1793			}
1794	
1795			// left-hand side and right-hand side of the connections to be made
1796			RTLIL::SigSpec cr;
1797			VariableBits cl, latch_driven;
1798	
1799			for (auto driven_bit : all_driven) {
1800				if (!dangling.count(driven_bit)) {
1801					// No latch inferred
1802					cl.append(driven_bit);
1803					cr.append(procedure.vstate.visible_assignments.at(driven_bit));
1804				} else {
1805					latch_driven.append(driven_bit);
1806				}
1807			}
1808	
1809			if (symbol.procedureKind == ast::ProceduralBlockKind::AlwaysLatch && !cl.empty()) {
1810				for (auto chunk : cl.chunks()) {
1811					auto &diag = netlist.add_diag(diag::LatchNotInferred, symbol.location);
1812					diag << chunk.text();
1813				}
1814			}
1815	
1816			if (!latch_driven.empty()) {
1817				// map from a driven signal to the corresponding enable/staging signal
1818				// TODO: SigSig needlessly costly here
1819				Yosys::dict<VariableBit, RTLIL::SigSig> signaling;
1820				RTLIL::SigSpec enables, all_staging;
1821	
1822				latch_driven.sort_and_unify();
1823				for (auto chunk : latch_driven.chunks()) {
1824					RTLIL::SigSpec en = netlist.add_placeholder_signal(chunk.bitwidth());
1825					RTLIL::SigSpec staging = netlist.add_placeholder_signal(chunk.bitwidth());
1826	
1827					for (uint64_t i = 0; i < chunk.bitwidth(); i++) {
1828						RTLIL::Cell *cell = netlist.canvas->addDlatch(netlist.new_id(), en[i],
1829												staging[i], netlist.convert_static(chunk[i]), true);
1830						netlist.driven_variables.insert(chunk[i]);
1831						netlist.register_driven_variables.insert(chunk[i]);
1832						transfer_attrs(netlist, symbol, cell);
